import React, { useEffect, useState } from "react";
import axios from "axios";

const Dashboard = () => {
  const [summary, setSummary] = useState({
    totalIncome: 0,
    totalExpenses: 0,
    balance: 0,
  });

  useEffect(() => {
    const fetchSummary = async () => {
      try {
        const token = localStorage.getItem("token");

        const res = await axios.get(
          "http://localhost:5000/api/dashboard/summary",
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        setSummary(res.data);
      } catch (err) {
        console.error(err);
      }
    };

    fetchSummary();
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <h1 className="text-3xl font-bold mb-8 text-gray-800">
        Financial Dashboard
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        
        {/* Income Card */}
        <div className="bg-green-500 text-white rounded-2xl shadow-lg p-6">
          <h2 className="text-lg font-semibold mb-2">Total Income</h2>
          <p className="text-3xl font-bold">₹{summary.totalIncome}</p>
        </div>

        {/* Expense Card */}
        <div className="bg-red-500 text-white rounded-2xl shadow-lg p-6">
          <h2 className="text-lg font-semibold mb-2">Total Expenses</h2>
          <p className="text-3xl font-bold">₹{summary.totalExpenses}</p>
        </div>

        {/* Balance Card */}
        <div className="bg-blue-500 text-white rounded-2xl shadow-lg p-6">
          <h2 className="text-lg font-semibold mb-2">Balance</h2>
          <p className="text-3xl font-bold">₹{summary.balance}</p>
        </div>
      </div>

      {/* Welcome Section */}
      <div className="mt-8 bg-white rounded-2xl shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-700 mb-2">
          Welcome to Finora AI
        </h2>
        <p className="text-gray-600">
          Track your income, monitor expenses, and manage your finances smarter.
        </p>
      </div>
    </div>
  );
};

export default Dashboard;
